import{A as e,f as t,h as n,t as r}from"./chunks/plugin-vue_export-helper.I53torQa.js";var i=JSON.parse(`{"title":"vLLM Ascend ACL Graph 详解","description":"深入剖析 ACL Graph 模式如何通过计算图捕获与批量下发减少 Host-Device 通信开销，提升 NPU 利用率。","frontmatter":{"title":"vLLM Ascend ACL Graph 详解","description":"深入剖析 ACL Graph 模式如何通过计算图捕获与批量下发减少 Host-Device 通信开销，提升 NPU 利用率。"},"headers":[],"relativePath":"inference/vllm/ascend-acl-graph.md","filePath":"inference/vllm/ascend-acl-graph.md","lastUpdated":1782802556000}`),a={name:`inference/vllm/ascend-acl-graph.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<h1 id="vllm-ascend-acl-graph-详解" tabindex="-1">vLLM Ascend ACL Graph 详解 <a class="header-anchor" href="#vllm-ascend-acl-graph-详解" aria-label="Permalink to “vLLM Ascend ACL Graph 详解”">​</a></h1><p>在大语言模型推理场景中，最大化 NPU 计算资源利用率并减少 Host 端调度开销是性能优化的关键。本文将深入探讨 vLLM Ascend 平台上的 ACL Graph 功能，从设计背景、核心机制到实现细节与当前限制，提供一份详尽的技术指南。</p><h2 id="_1-背景-为什么需要-acl-graph" tabindex="-1">1. 背景：为什么需要 ACL Graph <a class="header-anchor" href="#_1-背景-为什么需要-acl-graph" aria-label="Permalink to “1. 背景：为什么需要 ACL Graph”">​</a></h2><p>LLM 推理中，每个 Token 的生成都涉及数千个算子。在传统的 <strong>Eager Mode（即时执行模式）</strong> 下，Host（CPU）需要逐个向 Device（NPU）下发算子指令。</p><p>若 Host 下发速度慢于 Device 执行速度，就会出现 <strong>Host-Bound</strong> 现象。严重时，Device 可能一半以上时间处于空闲等待状态，造成巨大算力浪费。</p><p><strong>ACL Graph（图模式）</strong> 通过将计算图进行捕获并一次性下发，显著减少 Host 与 Device 之间的通信开销：</p><ul><li><p><strong>Eager Mode（串行交互）</strong>：</p><ul><li>Host：<code>Launch Op1 -&gt; Launch Op2 -&gt; Launch Op3 -&gt; ...</code></li><li>Device：<code>Run Op1 -&gt; Run Op2 -&gt; Run Op3 -&gt; ...</code></li><li><strong>痛点</strong>：通信间隙导致 Device 频繁空闲。</li></ul></li><li><p><strong>Graph Mode（批处理交互）</strong>：</p><ul><li>Host：<code>Launch Graph</code>（包含所有 Ops）</li><li>Device：<code>Run Op1 -&gt; Run Op2 -&gt; Run Op3 -&gt; ...</code></li><li><strong>优势</strong>：Device 连续执行，吞吐量最大化。</li></ul></li></ul><h2 id="_2-核心机制" tabindex="-1">2. 核心机制 <a class="header-anchor" href="#_2-核心机制" aria-label="Permalink to “2. 核心机制”">​</a></h2><p>ACL Graph 的工作流程主要分为两个阶段：</p><ol><li><strong>捕获（Capture）</strong>：引擎启动时通过一次模拟前向传播捕获所有算子并保存为图。</li><li><strong>重放（Replay）</strong>：实际请求到达时，直接在 Device 上重放该图。</li></ol><p>实际应用面临两个主要挑战：<strong>输入形状的动态性</strong>与<strong>复杂算子的兼容性</strong>。</p><h3 id="_2-1-填充与分桶-padding-and-bucketing" tabindex="-1">2.1 填充与分桶（Padding and Bucketing） <a class="header-anchor" href="#_2-1-填充与分桶-padding-and-bucketing" aria-label="Permalink to “2.1 填充与分桶（Padding and Bucketing）”">​</a></h3><p>图模式要求重放时的输入 Shape 必须与捕获时一致。然而 LLM 的输入 Shape 由调度器调度的请求决定，具有高度动态性。</p><ul><li><strong>暴力解法</strong>：按最大可能 Shape 捕获一张图，将所有输入 Padding 到最大长度。这会带来大量无效计算。</li><li><strong>优化解法（Bucketing）</strong>： <ol><li>设定一个阈值。</li><li><strong>低于阈值</strong>：预先捕获多个不同 Shape 的图（Bucket）。输入 Padding 到最近的 Bucket 大小，平衡计算效率与图复用率。</li><li><strong>高于阈值</strong>：认为此时 Tensor 较大、计算密集，Host 调度开销占比降低，回退到 <strong>Eager Mode</strong> 以避免 Padding 开销。</li></ol></li></ul><h3 id="_2-2-分段图与全图-piecewise-and-full-graph" tabindex="-1">2.2 分段图与全图（Piecewise and Full Graph） <a class="header-anchor" href="#_2-2-分段图与全图-piecewise-and-full-graph" aria-label="Permalink to “2.2 分段图与全图（Piecewise and Full Graph）”">​</a></h3><p>随着模型架构演进（如 MLA），Attention 层日益复杂。当 Batch 中同时包含 Prefill 与 Decode Token 时，统一图模式难以处理。</p><p>vLLM Ascend 提供两种策略：</p><h4 id="分段图-piecewise-graph" tabindex="-1">分段图（Piecewise Graph） <a class="header-anchor" href="#分段图-piecewise-graph" aria-label="Permalink to “分段图（Piecewise Graph）”">​</a></h4><ul><li><strong>原理</strong>：将模型切分，Attention 层使用 Eager Mode，其余层（MLP、LayerNorm）使用 Graph Mode。</li><li><strong>适用场景</strong>：无法运行全图的复杂 Attention 场景。</li><li><strong>缺点</strong>：相比全图，Host 下发开销依然存在；小 Batch 或弱 CPU 仍可能 Host-Bound。</li><li><strong>资源消耗</strong>：模型被切分为 <code>num_hidden_layers + 1</code> 个子模块，每个子模块作为独立图运行，消耗大量 Stream 资源。</li></ul><h4 id="全图-full-graph" tabindex="-1">全图（Full Graph） <a class="header-anchor" href="#全图-full-graph" aria-label="Permalink to “全图（Full Graph）”">​</a></h4><ul><li><strong>原理</strong>：包含 Attention 层在内的所有算子均在图中执行。</li><li><strong>优势</strong>：性能最优。</li><li><strong>实现难点</strong>：需在执行前更新 Attention 算子参数（如 Block Tables）。由于内存复用机制，必须使用特定 NPU 接口（<code>graph_task_update</code>）并配合事件（Event）同步，确保数据一致性。</li></ul><p><strong>调度策略优先级</strong>：</p><ol><li>首选 <strong>Full Graph</strong> 以获得最佳性能。</li><li>若全图不可用，降级为 <strong>Piecewise Graph</strong>。</li><li>若性能仍不理想，采取混合策略：Decode 阶段用全图，Prefill 阶段用 Eager Mode。</li></ol><h2 id="_3-实现细节" tabindex="-1">3. 实现细节 <a class="header-anchor" href="#_3-实现细节" aria-label="Permalink to “3. 实现细节”">​</a></h2><p>vLLM 在 Ascend 上的图模式实现主要依赖 <code>ACLGraphWrapper</code>：</p><ol><li><strong>装饰器拦截</strong>：<code>support_torch_compile</code> 装饰器替换模型类的 <code>__init__</code> 与 <code>forward</code> 接口。</li><li><strong>执行流</strong>：<code>forward</code> 被调用时，控制权移交给 <code>ACLGraphWrapper</code>，由其决定进行 Capture 还是 Replay。</li><li><strong>参数更新</strong>：全图模式下，Ascend 后端实现 <code>update_attn_params</code> 与 <code>update_mla_attn_params</code>，通过 <code>torch.npu.graph_task_update_begin/end</code> 在图执行任务中嵌入参数更新，确保内存复用时的正确性。</li></ol><h2 id="_4-资源约束与-dfx" tabindex="-1">4. 资源约束与 DFX <a class="header-anchor" href="#_4-资源约束与-dfx" aria-label="Permalink to “4. 资源约束与 DFX”">​</a></h2><h3 id="_4-1-stream-资源限制" tabindex="-1">4.1 Stream 资源限制 <a class="header-anchor" href="#_4-1-stream-资源限制" aria-label="Permalink to “4.1 Stream 资源限制”">​</a></h3><p>ACL Graph 的主要瓶颈在于 <strong>Stream（流）</strong> 资源：</p><ul><li>硬件 Stream 总数约 2048，预留部分后可用约 1800 个。</li><li>每个图至少占用 1 个独立 Stream。</li><li>每个通信域（Comm Domain）增加 1 个 Stream 消耗。</li><li><strong>Piecewise Graph 的挑战</strong>：模型被切分为数十个子图，Stream 消耗远高于全图模式。</li></ul><p>当前通过 <code>update_aclgraph_sizes</code> 函数动态计算最大支持的 Bucket 数量，防止 Stream 溢出。</p><h3 id="_4-2-当前限制" tabindex="-1">4.2 当前限制 <a class="header-anchor" href="#_4-2-当前限制" aria-label="Permalink to “4.2 当前限制”">​</a></h3><p>截至 v0.11.0+，存在以下限制：</p><ol><li>暂不支持显式配置 <code>FULL</code> 和 <code>FULL_AND_PIECEWISE</code> 模式（系统自动选择）。</li><li>启用 MTP（Multi-Token Prediction）且 <code>num_speculative_tokens &gt; 1</code> 时，需显式设置 <code>cudagraph_capture_sizes</code>。</li><li>暂不支持 <code>use_inductor</code> 后端。</li></ol><h2 id="_5-快速上手" tabindex="-1">5. 快速上手 <a class="header-anchor" href="#_5-快速上手" aria-label="Permalink to “5. 快速上手”">​</a></h2><p>在 vLLM Ascend 的 V1 Engine 中，<strong>ACL Graph 默认开启</strong>。确保配置中未设置 <code>enforce_eager=True</code>：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">python</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> -m</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> vllm.entrypoints.openai.api_server</span><span style="--shiki-light:#EE0000;--shiki-dark:#D7BA7D;"> \\</span></span>
<span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">  --model</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> /path/to/your/model</span><span style="--shiki-light:#EE0000;--shiki-dark:#D7BA7D;"> \\</span></span>
<span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">  --device</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> ascend</span></span>
<span class="line"><span style="--shiki-light:#008000;--shiki-dark:#6A9955;">  # 不要添加 --enforce-eager</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>更多详细配置请参考 <a href="https://docs.vllm.ai/en/latest/models/performance.html" target="_blank" rel="noreferrer">vLLM 性能文档</a>。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to “参考”">​</a></h2><ul><li><a href="https://vllm-ascend.readthedocs.io/" target="_blank" rel="noreferrer">vLLM Ascend Documentation</a></li><li><a href="https://www.hiascend.com/document/" target="_blank" rel="noreferrer">ACL Graph Official Guide</a></li></ul>`,40)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};